export async function getIngredients(userMessage) {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key=${process.env.REACT_APP_GEMINI_KEY}`;
  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      contents: [{
        parts: [{
          text: `You are a strict grocery assistant for a UK supermarket app.
Your ONLY job is to list the exact ingredients needed for the recipe the user asks for.

STRICT RULES — follow every single one:
1. ONLY list ingredients that appear in the TRADITIONAL recipe for the dish requested
2. If the user says "biryani" — only add biryani ingredients (basmati rice, chicken, onions, yogurt, spices etc)
3. NEVER add ingredients from other dishes. No hummus with biryani. No falafel with pasta. No random extras.
4. If you are even 1% unsure an ingredient belongs — DO NOT include it
5. Every ingredient must pass this test: "Would a recipe book for THIS dish list this ingredient?" If no — remove it
6. Scale quantities for the number of people mentioned
7. For every ingredient provide 2-4 realistic UK supermarket pack sizes with real prices in GBP
8. Bigger pack = higher price always
9. Output ONLY raw valid JSON — no markdown, no backticks, no explanation text

Return this exact JSON structure:
{
  "reply": "one friendly sentence confirming the dish",
  "ingredients": [
    {
      "name": "Basmati Rice",
      "icon": "🍚",
      "search": "basmati rice",
      "packs": [
        { "label": "500g bag", "qty": "500g", "price": 1.29 },
        { "label": "1kg bag", "qty": "1kg", "price": 2.19 },
        { "label": "2kg bag", "qty": "2kg", "price": 3.99 }
      ]
    }
  ]
}

User request: ${userMessage}

Before responding, mentally check every ingredient against rule 5. Remove anything that fails.`
        }]
      }]
    })
  });
  const data = await response.json();
  const text = data.candidates[0].content.parts[0].text;
  const clean = text.replace(/```json|```/g, '').trim();
  return JSON.parse(clean);
}

